#include<bits/stdc++.h>
using namespace std;
struct node
{
    int l,r,score,len,f;
    bool operator<(const node&b)const
    {
        return l<b.l;
    }
}a[10005];
int dp[1003][1003];
int main()
{
    int l,n,b;
    scanf("%d%d%d",&l,&n,&b);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d%d",&a[i].l,&a[i].len,&a[i].score,&a[i].f);
        a[i].r=a[i].l+a[i].len;
    }
    memset(dp,-1,sizeof(dp));
    dp[0][0]=0;
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j+a[i].f<=b;j++)
        {
            if(dp[a[i].l][j]==-1)
            {
                continue;
            }
            dp[a[i].r][j+a[i].f]=max(dp[a[i].r][j+a[i].f],dp[a[i].l][j]+a[i].score);
        }
    }
    int ans=-1;
    for(int i=0;i<=b;i++)
    {
        ans=max(ans,dp[l][i]);
    }
    printf("%d",ans);
    return 0;
}
